#include<bits/stdc++.h>
using namespace std;
int n,m,len,c[2000010],k,cnt[2000010];
long long sum,ans1[2000010],ans2[2000010];
struct query
{
    int l,r,id;
    bool operator<(const query&b)const
    {
        if(l/len!=b.l/len)
        {
            return l<b.l;
        }
        return (((l/len)&1)?r<b.r:r>b.r);
    }
}a[200010];
void add(int x)
{
    sum+=cnt[c[x]];
    cnt[c[x]]++;
}
void del(int x)
{
    cnt[c[x]]--;
    sum-=cnt[c[x]];
}
int main()
{
    scanf("%d%d",&n,&m);
    len=sqrt(n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
    }
    for(int i=0;i<m;i++)
    {
        scanf("%d%d",&a[i].l,&a[i].r);
        a[i].id=i;
    }
    sort(a,a+m);
    int l=1,r=0;
    for(int i=0;i<m;i++)
    {
        if(a[i].l==a[i].r)
        {
            ans1[a[i].id]=0;
            ans2[a[i].id]=1;
            continue;
        }
        while(l>a[i].l)
        {
            add(--l);
        }
        while(r<a[i].r)
        {
            add(++r);
        }
        while(l<a[i].l)
        {
            del(l++);
        }
        while(r>a[i].r)
        {
            del(r--);
        }
        ans1[a[i].id]=sum;
        ans2[a[i].id]=1ll*(r-l+1)*(r-l)/2;
    }
    for(int i=0;i<m;i++)
    {
        if(ans1[i]!=0)
        {
            long long g=__gcd(ans1[i],ans2[i]);
            ans1[i]/=g;
            ans2[i]/=g;
        }
        else
        {
            ans2[i]=1;
        }
        printf("%lld/%lld\n",ans1[i],ans2[i]);
    }
    return 0;
}
